args.sparql:
SELECT ?country WHERE {
  ?event wdt:P31 wd:Q2772679;
         wdt:P585 ?eventDate;
         rdfs:label "2017 Pan American Fencing Championships"@en.
  FILTER (year(?eventDate) = 2017 && month(?eventDate) = 6 && day(?eventDate) >= 13 && day(?eventDate) <= 18).

  ?event wdt:P2015 ?participant.
  ?participant p:P1346/ps:P1346 ?position.
  FILTER (CONTAINS(?position, "4th") || ?position = "4"^^xsd:integer).

  ?participant wdt:P17 ?country.
  ?country wdt:P36 wd:Q1168.
}

SELECT ?country WHERE {
  ?event rdfs:label "2017 Pan American Fencing Championships"@en;
         wdt:P1264 ?startDate;
         wdt:P1265 ?endDate;
         wdt:P31 wd:Q2772679.
  FILTER ( ?startDate <= "2017-06-18"^^xsd:date &&
           ?endDate >= "2017-06-13"^^xsd:date )
  ?country p:P1346 ?rankStatement;
           ps:P1346 ?rank.
  ?rankStatement pq:P1346 ?event.
  FILTER (CONTAINS(?rank, "4th") || STR(?rank) = "4")
  ?country wdt:P36 wd:Q1168.
}

SELECT ?participant WHERE {
  ?event wdt:P31 wd:Q2772679;
         rdfs:label "2017 Pan American Fencing Championships"@en;
         wdt:P585 ?eventDate.
  FILTER (year(?eventDate) = 2017 && month(?eventDate) = 6 && day(?eventDate) >= 13 && day(?eventDate) <= 18).
  ?event wdt:P1089 ?participant.
  ?participant wdt:P1346 ?rank.
  FILTER (CONTAINS(?rank, "4th") || ?rank = "4")
  ?participant wdt:P36 wd:Q1168.
}

SELECT ?country WHERE {
  ?event wdt:P31 wd:Q2772679;
         rdfs:label "2017 Pan American Fencing Championships"@en;
         wdt:P1264 ?start;
         wdt:P1265 ?end.

  FILTER ( ?start <= "2017-06-18"^^xsd:date && ?end >= "2017-06-13"^^xsd:date ).

  ?country wdt:P1089 ?event;
          wdt:P1346 ?rank;
          wdt:P36 wd:Q1168.

  FILTER (CONTAINS(?rank, "4th") || ?rank = "4").
}

SELECT ?participant WHERE {
  ?event rdfs:label "2017 Men's Pan American Fencing Championship"@en ;
          wdt:P31 wd:Q2772679 ;
          wdt:P1264 ?start ;
          wdt:P1265 ?end .
  FILTER ( ?start <= "2017-06-18"^^xsd:date && ?end >= "2017-06-13"^^xsd:date ).
  ?participant wdt:P1089 ?event ;
              wdt:P1346 ?rank ;
              wdt:P36 wd:Q22200 .
  FILTER (STR(?rank) = "4th")
}

